import{_ as a,o as i,i as l,aB as o}from"./chunks/framework.CoTX8EIa.js";const u=JSON.parse('{"title":"fa-page-optimizer","description":"","frontmatter":{},"headers":[],"relativePath":"guide/skills/fa-page-optimizer.md","filePath":"guide/skills/fa-page-optimizer.md"}'),d={name:"guide/skills/fa-page-optimizer.md"};function t(s,e,c,r,n,p){return i(),l("div",null,[...e[0]||(e[0]=[o(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /guide/skills/fa-page-optimizer.md for this page in Markdown format</div><h1 id="fa-page-optimizer" tabindex="-1">fa-page-optimizer <a class="header-anchor" href="#fa-page-optimizer" aria-label="Permalink to “fa-page-optimizer”">​</a></h1><p><code>fa-page-optimizer</code> 用来重构已经存在的 Vue 页面。它会优先使用 Fantastic-admin 内建的 <code>Fa*</code> 组件和工具函数，替换原生 HTML、重复造轮子的自定义实现，以及风格不统一的页面壳层，在尽量不改业务逻辑的前提下，把页面拉回框架统一的交互和视觉体系。</p><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to “适用场景”">​</a></h2><ul><li>页面结构太乱、风格不统一</li><li>页面里有大量原生 HTML 或重复自定义实现</li><li>希望用框架内建 <code>Fa*</code> 组件替换现有实现</li><li>希望保留现有接口、权限和业务逻辑，只优化视图层与页面结构</li></ul><h2 id="使用方式" tabindex="-1">使用方式 <a class="header-anchor" href="#使用方式" aria-label="Permalink to “使用方式”">​</a></h2><p>直接说明以下信息即可：</p><ul><li>目标应用，例如 <code>example</code></li><li>需要优化的页面文件或目录</li><li>希望替换或优化的内容，例如搜索区、卡片容器、弹窗、分页、空态、加载状态</li><li>是否允许顺手拆分子组件或整理模板结构</li><li>是否要求不改业务逻辑</li></ul><p>示例：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>在 example 应用里优化用户列表页。</span></span>
<span class="line"><span>文件是 apps/example/src/views/system/user/index.vue。</span></span>
<span class="line"><span>把原生按钮、搜索区域、分页和删除确认弹窗替换成 Fa 组件，不要改业务逻辑。</span></span></code></pre></div><h2 id="常见优化内容" tabindex="-1">常见优化内容 <a class="header-anchor" href="#常见优化内容" aria-label="Permalink to “常见优化内容”">​</a></h2><ul><li>用 <code>FaCard</code> 收敛页面容器、标题区、操作区和底部区域</li><li>用 <code>FaSearchBar</code> 替换手写搜索表单或零散筛选输入</li><li>用 <code>FaButton</code>、<code>FaButtonGroup</code> 统一操作按钮的样式、尺寸和状态</li><li>用 <code>FaModal</code>、<code>FaDrawer</code>、<code>useFaModal()</code> 替换自定义弹层与确认逻辑</li><li>用 <code>FaPagination</code>、<code>FaEmpty</code>、<code>FaLoading</code>、<code>useFaLoading()</code> 统一列表状态</li><li>用 <code>faToast()</code> 替换零散的成功、失败、警告提示调用</li></ul><h2 id="结果" tabindex="-1">结果 <a class="header-anchor" href="#结果" aria-label="Permalink to “结果”">​</a></h2><p>通常会修改已有页面文件，例如：</p><ul><li><code>apps/&lt;app&gt;/src/views/.../*.vue</code></li><li><code>apps/&lt;app&gt;/src/views/.../components/*.vue</code>（按需拆分）</li></ul><p>常见结果包括：</p><ul><li>用 <code>FaButton</code>、<code>FaCard</code>、<code>FaModal</code>、<code>FaPagination</code> 等替换现有实现</li><li>优化页面结构与样式</li><li>保留原有业务逻辑、接口调用和权限判断</li><li>让页面更贴近 Fantastic-admin 已有页面的交互方式与视觉风格</li></ul>`,17)])])}const m=a(d,[["render",t]]);export{u as __pageData,m as default};
